def valid_isbn(isbn):
    d=isbn.replace('-','').replace(' ','')
    if len(d)!=10: return False
    t=0
    for i,ch in enumerate(d):
        if ch=='X' and i==9: t+=10*(10-i)
        elif ch.isdigit(): t+=int(ch)*(10-i)
        else: return False
    return t%11==0

response:
def test_isbn_v():
    assert valid_isbn('0-306-40615-2')==True
    assert valid_isbn('1234567890')==False
import pytest; pytest.main()

